const args = JSON.parse(ARGS);
const unitName = args.unit_name;
const dates = args.dates;
const parts = dates.split('->').map(s => s.trim());
const start = new Date(parts[0]);
const end = new Date(parts[1]);
const prices = [];
let total = 0;
const d = new Date(start);
while (d < end) {
  const isWeekend = (d.getDay() === 0 || d.getDay() === 6);
  const price = isWeekend ? 1200000 : 850000;
  prices.push({ date: d.toISOString().split('T')[0], price: price, available: true });
  total += price;
  d.setDate(d.getDate() + 1);
}
console.log(JSON.stringify({ unit_name: unitName, dates: dates, currency: "IDR", prices: prices, total: total, nights: prices.length }));
